const item = $input.first();
const now = new Date();
const stamp = now.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, '').replace('T', '-');
const random = Math.random().toString(16).slice(2, 8).padEnd(6, '0');
const jobId = `${stamp}-${random}`;
const baseDir = ($env.VIDEO_CLIP_JOBS_DIR || '/tmp/n8n-video-jobs').replace(/\/+$/, '');
const repoDir = ($env.VIDEO_CLIP_REPO_DIR || '/Users/stephenqiu/Desktop/Repository/n8n').replace(/\/+$/, '');
const jobDir = `${baseDir}/${jobId}`;
return [{ json: { jobId, baseDir, repoDir, jobDir, inputsDir: `${jobDir}/inputs`, ttsDir: `${jobDir}/tts`, renderDir: `${jobDir}/render` }, binary: item.binary }];

const fs = require('fs');
const item = $input.first();
const binary = item.binary || {};
const keyAliases = {
  coverImage: ['cover_image', 'coverImage'],
  screenshotImage: ['proof_screenshot', 'proofScreenshot'],
  scriptText: ['tts_script', 'ttsScript'],
  backgroundVideo: ['background_video', 'backgroundVideo']
};
function firstBinaryKey(keys) {
  return keys.find((key) => binary[key]);
}
const uploadKeys = {
  coverImage: firstBinaryKey(keyAliases.coverImage),
  screenshotImage: firstBinaryKey(keyAliases.screenshotImage),
  scriptText: firstBinaryKey(keyAliases.scriptText),
  backgroundVideo: firstBinaryKey(keyAliases.backgroundVideo)
};
for (const [name, key] of Object.entries(uploadKeys)) {
  if (!key) throw new Error(`Missing uploaded file: ${name}. Accepted field names: ${keyAliases[name].join(', ')}`);
}
fs.mkdirSync(item.json.inputsDir, { recursive: true });
fs.mkdirSync(item.json.ttsDir, { recursive: true });
fs.mkdirSync(item.json.renderDir, { recursive: true });
const files = {
  coverImage: `${item.json.inputsDir}/cover.png`,
  screenshotImage: `${item.json.inputsDir}/screenshot.png`,
  scriptText: `${item.json.inputsDir}/script.txt`,
  backgroundVideo: `${item.json.inputsDir}/background.mp4`
};
for (const [inputName, target] of [['coverImage', files.coverImage], ['screenshotImage', files.screenshotImage], ['backgroundVideo', files.backgroundVideo]]) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, uploadKeys[inputName]);
  fs.writeFileSync(target, buffer);
}
const scriptBuffer = await this.helpers.getBinaryDataBuffer(0, uploadKeys.scriptText);
const scriptText = scriptBuffer.toString('utf-8').replace(/\r\n/g, '\n').replace(/\r/g, '\n').replace(/\n{3,}/g, '\n\n').trim();
if (!scriptText) throw new Error('TTS script is empty');
fs.writeFileSync(files.scriptText, scriptText, 'utf8');
return [{ json: { ...item.json, files, scriptText }, binary }];

const fs = require('fs');
const previous = $('Save Uploaded Files').first().json;
const responseItem = $input.first().json;
const raw = typeof responseItem.data === 'string' ? responseItem.data : JSON.stringify(responseItem);
const responsePath = `${previous.ttsDir}/tts-response.jsonstream`;
fs.writeFileSync(responsePath, raw);
function parseJsonStream(text) {
  const frames = [];
  let index = 0;
  while (index < text.length) {
    while (index < text.length && /\s/.test(text[index])) index += 1;
    if (index >= text.length) break;
    let depth = 0;
    let inString = false;
    let escaped = false;
    let end = index;
    for (; end < text.length; end += 1) {
      const ch = text[end];
      if (inString) {
        if (escaped) escaped = false;
        else if (ch === '\\') escaped = true;
        else if (ch === '"') inString = false;
        continue;
      }
      if (ch === '"') inString = true;
      else if (ch === '{') depth += 1;
      else if (ch === '}') {
        depth -= 1;
        if (depth === 0) { end += 1; break; }
      }
    }
    if (end <= index || depth !== 0) break;
    frames.push(JSON.parse(text.slice(index, end)));
    index = end;
  }
  return frames;
}
const frames = parseJsonStream(raw);
const audioBase64Chunks = frames.map((frame) => frame.data).filter((data) => typeof data === 'string' && data.length > 0);
if (audioBase64Chunks.length === 0) {
  const first = frames[0] || responseItem;
  const code = first?.code || first?.header?.code || 'unknown';
  const message = first?.message || first?.header?.message || 'Doubao TTS response did not include audio chunks';
  throw new Error(`Doubao TTS failed: ${code} ${message}`);
}
const audioPath = `${previous.ttsDir}/audio.mp3`;
const audio = Buffer.concat(audioBase64Chunks.map((chunk) => Buffer.from(chunk, 'base64')));
fs.writeFileSync(audioPath, audio);
if (fs.statSync(audioPath).size === 0) throw new Error('Doubao TTS audio is empty');
return [{ json: { ...previous, audioPath, ttsResponsePath: responsePath, ttsFrames: frames.length, ttsAudioChunks: audioBase64Chunks.length } }];

const fs = require('fs');
const item = $input.first().json;
const job = {
  jobId: item.jobId,
  inputs: {
    coverImage: item.files.coverImage,
    screenshotImage: item.files.screenshotImage,
    backgroundVideo: item.files.backgroundVideo,
    scriptText: item.files.scriptText,
    ttsAudio: item.audioPath
  },
  output: {
    video: `${item.renderDir}/final.mp4`,
    subtitles: `${item.renderDir}/subtitles.ass`,
    ffmpegLog: `${item.renderDir}/ffmpeg.log`
  },
  video: { width: 1920, height: 1080, fps: 30, coverDuration: 3, screenshotDuration: 4 },
  layout: { coverTop: { x: 80, y: 60, width: 560 }, screenshotTop: { x: 1280, y: 60, width: 560 }, subtitleBottomMargin: 90 }
};
const jobPath = `${item.jobDir}/job.json`;
fs.writeFileSync(jobPath, JSON.stringify(job, null, 2));
return [{ json: { ...item, jobPath, outputVideo: job.output.video, ffmpegLog: job.output.ffmpegLog } }];

const { spawn } = require('child_process');
const item = $input.first().json;
const scriptPath = `${item.repoDir}/tools/video-composer/compose-video.mjs`;
function runComposer() {
  return new Promise((resolve, reject) => {
    const child = spawn('node', [scriptPath, item.jobPath], {
      cwd: item.repoDir,
      stdio: ['ignore', 'pipe', 'pipe']
    });
    let stdout = '';
    let stderr = '';
    const maxOutput = 1024 * 1024 * 20;
    child.stdout.on('data', (chunk) => {
      stdout += chunk.toString('utf8');
      if (stdout.length > maxOutput) stdout = stdout.slice(-maxOutput);
    });
    child.stderr.on('data', (chunk) => {
      stderr += chunk.toString('utf8');
      if (stderr.length > maxOutput) stderr = stderr.slice(-maxOutput);
    });
    child.on('error', reject);
    child.on('close', (code, signal) => {
      if (code === 0) {
        resolve({ stdout, stderr });
        return;
      }
      const detail = [stdout, stderr].filter(Boolean).join('\n').trim();
      reject(new Error(`Video composer failed with exit code ${code}${signal ? ` signal ${signal}` : ''}${detail ? `:\n${detail}` : ''}`));
    });
  });
}
const result = await runComposer();
return [{ json: { ...item, composerStdout: result.stdout || '', composerStderr: result.stderr || '' } }];

const fs = require('fs');
const item = $('Build Job Config').first().json;
if (!fs.existsSync(item.outputVideo)) {
  throw new Error(`Final video was not created: ${item.outputVideo}`);
}
const size = fs.statSync(item.outputVideo).size;
if (size === 0) throw new Error(`Final video is empty: ${item.outputVideo}`);
return [{ json: { jobId: item.jobId, jobDir: item.jobDir, videoPath: item.outputVideo, ffmpegLog: item.ffmpegLog, size } }];
